import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import TicketVenta from "../components/TicketVenta";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);
  const [clienteNombre, setClienteNombre] = useState("");
  const [clienteApellido, setClienteApellido] = useState("");
  const [clienteTelefono, setClienteTelefono] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [carrito, setCarrito] = useState([]);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  /* =========================
     OBTENER DATOS
  ========================== */

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (err) {
      console.error("❌ Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  /* =========================
     BUSCAR PRODUCTO
  ========================== */

  const buscarProducto = (texto) => {
    setBusquedaProducto(texto);

    const producto = productos.find((p) =>
      (p.Nombre || p.nombre || "")
        .toLowerCase()
        .includes(texto.toLowerCase())
    );

    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  /* =========================
     AGREGAR AL CARRITO
  ========================== */

  const agregarAlCarrito = () => {
    if (!productoSeleccionado || cantidad <= 0) return;

    const stock = Number(productoSeleccionado.Stock ?? productoSeleccionado.stock ?? 0);

    if (stock < cantidad) {
      setMensaje("❌ Stock insuficiente.");
      return;
    }

    const productID = productoSeleccionado.ProductoID || productoSeleccionado.id;
    const precio = Number(productoSeleccionado.Precio || productoSeleccionado.precio);

    const existente = carrito.find((p) => p.ProductID === productID);

    if (existente) {
      setCarrito(
        carrito.map((p) =>
          p.ProductID === productID
            ? { ...p, Cantidad: p.Cantidad + cantidad }
            : p
        )
      );
    } else {
      setCarrito([
        ...carrito,
        {
          ProductID: productID,
          Nombre: productoSeleccionado.Nombre || productoSeleccionado.nombre,
          Cantidad: cantidad,
          PrecioUnitario: precio,
        },
      ]);
    }

    setProductoSeleccionado(null);
    setBusquedaProducto("");
    setCantidad(1);
  };

  /* =========================
     CALCULOS
  ========================== */

  const calcularSubtotal = () =>
    carrito.reduce((acc, p) => acc + p.Cantidad * p.PrecioUnitario, 0);

  /* =========================
     REALIZAR VENTA
  ========================== */
const realizarVenta = async () => {
  if (!clienteNombre.trim() || !clienteApellido.trim()) {
    setMensaje("⚠️ Ingresa nombre y apellido del cliente.");
    return;
  }

  if (carrito.length === 0) {
    setMensaje("⚠️ El carrito está vacío.");
    return;
  }

  try {
    // Buscar cliente existente
    let cliente = clientes.find(
      (c) =>
        (c.Nombre || c.nombre || "").toLowerCase() === clienteNombre.toLowerCase() &&
        (c.Apellido || c.apellido || "").toLowerCase() === clienteApellido.toLowerCase()
    );

    let ClienteID = cliente?.ClienteID || cliente?.id || null;

    // Si no existe cliente, se envían los datos para que el backend lo cree
    const payload = {
      ClienteID,
      Nombre: clienteNombre,
      Apellido: clienteApellido,
      Telefono: clienteTelefono || "",
      EmisorNombre: "Sistema de ventas",
      productos: carrito.map((p) => ({
        ProductID: p.ProductID,
        Cantidad: p.Cantidad
      }))
    };

    await axios.post("http://localhost:5000/api/ventas", payload);
    setTicket(res.data);

    setMensaje("✅ Venta realizada correctamente.");
    setCarrito([]);
    setClienteNombre("");
    setClienteApellido("");
    setClienteTelefono("");
    obtenerProductos();
  } catch (err) {
    console.error("❌ Error al realizar venta:", err.response?.data || err);
    setMensaje("❌ Error interno al registrar la venta.");
  }
};

  /* =========================
     RENDER
  ========================== */

  return (
    <div className="container mt-5">
      <div className="row">
        {/* FORMULARIO */}
        <div className="col-md-6">
          <div className="card shadow p-4 mb-4">
            <h5 className="fw-bold mb-3">Agregar Productos</h5>

            <input
              type="text"
              className="form-control mb-3"
              placeholder="Buscar producto..."
              value={busquedaProducto}
              onChange={(e) => buscarProducto(e.target.value)}
              list="listaProductos"
            />

            <datalist id="listaProductos">
              {productos.map((p) => (
                <option key={p.ProductoID || p.id} value={p.Nombre || p.nombre} />
              ))}
            </datalist>

            {productoSeleccionado && (
              <div className="mb-3">
                <p className="text-success">
                  Stock: {productoSeleccionado.Stock || productoSeleccionado.stock}
                </p>
                <div className="d-flex gap-2">
                  <input
                    type="number"
                    className="form-control"
                    min="1"
                    value={cantidad}
                    onChange={(e) => setCantidad(Number(e.target.value))}
                  />
                  <button className="btn btn-primary" onClick={agregarAlCarrito}>
                    ➕ Agregar
                  </button>
                </div>
              </div>
            )}

            <h5 className="fw-bold mt-4">Cliente</h5>
            <input
              className="form-control mb-2"
              placeholder="Nombre"
              value={clienteNombre}
              onChange={(e) => setClienteNombre(e.target.value)}
            />
            <input
              className="form-control mb-2"
              placeholder="Apellido"
              value={clienteApellido}
              onChange={(e) => setClienteApellido(e.target.value)}
            />
            <input
              className="form-control mb-2"
              placeholder="Teléfono"
              value={clienteTelefono}
              onChange={(e) => setClienteTelefono(e.target.value)}
            />

            {mensaje && <div className="alert alert-info mt-2">{mensaje}</div>}
          </div>
        </div>

        {/* CARRITO */}
        <div className="col-md-6">
          <div className="card shadow p-4 mb-4">
            <h5 className="fw-bold mb-3">Carrito</h5>

            {carrito.length === 0 ? (
              <p>No hay productos.</p>
            ) : (
              <table className="table table-sm">
                <tbody>
                  {carrito.map((p, i) => (
                    <tr key={i}>
                      <td>{p.Nombre}</td>
                      <td>{p.Cantidad}</td>
                      <td>${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}

            <p className="fw-bold">
              Total: ${(calcularSubtotal() * 1.13).toFixed(2)}
            </p>

            <button
              className="btn btn-success w-100"
              onClick={realizarVenta}
            >
              💰 Realizar Venta
            </button>
          </div>
        </div>
      </div>

      <TicketVenta ticket={ticket} setTicket={setTicket} />
    </div>
  );
}
